import { MarkdownExit } from 'markdown-exit';

declare function renderCode(md: MarkdownExit, renderOptions: ShikiOptions): void;
export default renderCode;

declare interface ShikiOptions {
    themes: Record<string, string>;
    exclude_languages?: string[];
    language_aliases?: Record<string, string>;
    transformers?: string[];
    style_to_class?: {
        enable?: boolean;
        class_prefix?: string;
        css_output_path?: string;
    };
    code_collapse?: number;
    toolbar_items?: {
        lang?: boolean;
        title?: boolean;
        wrapToggle?: boolean;
        copyButton?: boolean;
    };
}

export { }
